final class WeakScriptMessageHandler: NSObject, WKScriptMessageHandler {
    weak var delegate: WKScriptMessageHandler?

    init(delegate: WKScriptMessageHandler) {
        self.delegate = delegate
    }

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        delegate?.userContentController(userContentController, didReceive: message)
    }
}

final class InAppPurchaseManager: NSObject {
    enum PurchaseError: LocalizedError {
        case paymentsDisabled
        case productNotFound
        case failed(String)
        case cancelled

        var errorDescription: String? {
            switch self {
            case .paymentsDisabled:
                return "Payments are disabled on this device."
            case .productNotFound:
                return "Product not found."
            case .failed(let message):
                return message
            case .cancelled:
                return "Purchase cancelled."
            }
        }
    }

    private var completion: ((Result<String, Error>) -> Void)?
    private var requestedProductIdentifier: String?

    func purchase(productIdentifier: String, completion: @escaping (Result<String, Error>) -> Void) {
        guard SKPaymentQueue.canMakePayments() else {
            completion(.failure(PurchaseError.paymentsDisabled))
            return
        }

        self.completion = completion
        self.requestedProductIdentifier = productIdentifier

        let request = SKProductsRequest(productIdentifiers: [productIdentifier])
        request.delegate = self
        request.start()
    }
}

extension InAppPurchaseManager: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        guard let product = response.products.first else {
            completion?(.failure(PurchaseError.productNotFound))
            cleanup()
            return
        }

        SKPaymentQueue.default().add(self)
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }
}

extension InAppPurchaseManager: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased, .restored:
                let transactionId = transaction.transactionIdentifier ?? UUID().uuidString
                completion?(.success(transactionId))
                queue.finishTransaction(transaction)
                cleanup()
            case .failed:
                let error = (transaction.error as? SKError)?.code == .paymentCancelled
                    ? PurchaseError.cancelled
                    : PurchaseError.failed(transaction.error?.localizedDescription ?? "Unknown purchase error.")
                completion?(.failure(error))
                queue.finishTransaction(transaction)
                cleanup()
            case .purchasing, .deferred:
                break
            @unknown default:
                break
            }
        }
    }

    private func cleanup() {
        SKPaymentQueue.default().remove(self)
        completion = nil
        requestedProductIdentifier = nil
    }
}

